'use client';
import { Pencil, Trash2, Plus } from 'lucide-react';
import { useEffect, useState } from 'react';

export default function UserManagementTable() {
  const [categoreis,setCategories] = useState([])
   async function fetchCategoris(){
        const response = await fetch("http://localhost:5000/api/category")
        const data = await response.json()
        console.log(data.categoreis)
    }
    useEffect(
    ()=>{
      fetchCategoris() 

    },
    []
    )
    return
  return (
    
    <div className="p-6">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">User Management</h1>

        <button className="flex items-center gap-2 px-4 py-2 bg-orange-400 cursor-pointer text-white rounded-lg hover:scale-x-105 transition">
          <Plus size={18} />
          Add User
        </button>
      </div>

      {/* Table */}
      <div className="overflow-x-auto  rounded-xl">
        <table className="min-w-full text-left">
          <thead className="bg-gray-50 border-b">
            <tr>
              <th className="px-4 py-3 text-md font-medium text-gray-600">Name</th>
              <th className="px-4 py-3 text-md font-medium text-gray-600">Email</th>
              <th className="px-4 py-3 text-md font-medium text-gray-600">Role</th>
              <th className="px-4 py-3 text-md font-medium text-gray-600">Status</th>
              <th className="px-4 py-3 text-md font-medium text-gray-600">Actions</th>
            </tr>
          </thead>

          <tbody>
            {users.map((user) => (
              <tr key={user.id} className="border-b text-md hover:bg-gray-50 transition">
                <td className="px-4 py-3 font-medium">{user.name}</td>
                <td className="px-4 py-3 text-gray-600">{user.email}</td>
                <td className="px-4 py-3">{user.role}</td>

                <td className="px-4 py-3">
                  <span 
                    className={`px-2 py-1 text-xs rounded-full ${
                      user.status === 'Active'
                        ? 'bg-green-100 text-green-700'
                        : 'bg-red-100 text-red-700'
                    }`}
                  >
                    {user.status}
                  </span>
                </td>

                <td className="px-4 py-3">
                  <div className="flex items-center gap-3">
                    <button className="text-blue-600 hover:text-blue-800 transition">
                      <Pencil size={18} />
                    </button>

                    <button className="text-red-600 hover:text-red-800 transition">
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}